    'home.brandStatement.title': 'Embarcações Infláveis de Qualidade Desde 2012',
    'home.brandStatement.text': 'Fabricante direto de barcos infláveis, SUPs, caiaques, RIBs e equipamentos de segurança marítima certificados CE →confiável por profissionais e entusiastas em mais de 50 países.',
    'home.brandStatement.pill1': 'Certificado CE',
