    'disasterRelief.a1': 'Záchranné operace',
    'disasterRelief.a1desc': 'Lokalizace a evakuace uvězněných osob v zaplavených městských nebo venkovských oblastech. Výjimečná manévrovatelnost v troskami posetých vodách a mělkých hloubkách.',
    'disasterRelief.a2': 'Lékařská evakuace',
    'disasterRelief.a2desc': 'Přeprava zraněných osob do zdravotnických zařízení. Čluny lze nakonfigurovat pro přepravu nosítek a důležitého lékařského vybavení.',
    'disasterRelief.a3': 'Logistika a zásobování',
    'disasterRelief.a3desc': 'Dodávky potravin, pitné vody, přístřešků a nezbytných zásob postiženým obyvatelům v říčních a pobřežních oblastech.',
    'disasterRelief.a4': 'Přeprava osob',
    'disasterRelief.a4desc': 'Přeprava hodnotících týmů, záchranářů a specializovaného personálu do a z postižených zón pro efektivní koordinaci zásahu.',
    'disasterRelief.a5': 'Posouzení škod',
    'disasterRelief.a5desc': 'Rychlé počáteční posouzení škod na pobřežních a vnitrozemských vodních cestách, které poskytuje klíčové informace pro plánování a přidělování zdrojů.',
    'disasterRelief.advantageDesc': 'Každý člun prochází před dodáním 24?hodinovým tlakovým testem. Naše materiály jsou testovány na UV degradaci, chemickou odolnost, oděr a pevnost v tahu. Za naše produkty ručíme komplexní dokumentací a rychlým zákaznickým servisem.',
    'disasterRelief.advantageTitle': 'Výhoda Seekingtex',
    'disasterRelief.badge': 'Humanitární mise',
    'disasterRelief.cta': 'Poptat humanitární ceny',
    'disasterRelief.desc': 'Nafukovací čluny Seekingtex navržené pro pomoc při katastrofách a humanitární pomoc. Rychlá připravenost k nasazení, extrémní odolnost, přístup do mělkých vod a konfigurace připravené pro SAR, MEDEVAC a logistiku.',
    'disasterRelief.expSub': 'Jak nafukovací čluny Seekingtex podporují pomoc při katastrofách a humanitární mise po celém světě.',
