    'searchRescue.f3desc': 'Scurgere rapidă a apei',
    'searchRescue.f4desc': 'Inele D din oțel inoxidabil rezistente la sarcini mari',
    'searchRescue.f5': 'Cusături sudate',
    'searchRescue.f5desc': 'Legătură moleculară →mai puternică decât țesătura însăși',
